import { useEffect, useState } from "react";
import { useParams } from "@remix-run/react";
import { useSelectListingStore } from "@/permissionless-listing/store/useListingStore";
import { PageView } from "@/permissionless-listing/types";
import DashboardLayout from "@/components/layouts/DashboardLayout";
import ListingBody from "@/permissionless-listing/sections/body";

export default function PermissionlessListingSymbolPage() {
  const params = useParams<{ symbol: string }>();
  const symbol = params.symbol ?? "";
  const [ready, setReady] = useState(false);
  const { setPage } = useSelectListingStore(s => ({
    setPage: s.setPage,
  }));

  useEffect(() => {
    if (!symbol) return;
    setPage(PageView.SymbolDetail, { symbol });
    setReady(true);
  }, [symbol, setPage]);

  return (
    <DashboardLayout title="Permissionless listing">
      {ready ? <ListingBody /> : null}
    </DashboardLayout>
  );
}
